def fizz_buzz(n: int):
    """Return the number of times the digit 7 appears in integers less than n which are divisible by 11 or 13."""
    count = 0
    for i in range(11, n, 11):
        for digit in str(i):
            if digit == '7':
                count += 1
    for i in range(13, n, 13):
        for digit in str(i):
            if digit == '7':
                count += 1
    return count
